        """
        初始化多智能体环境包装器。

        Args:
            env: 已配置好机器的 QuantumSchedulingEnv 实例
        """
        self.env = env
        self.num_agents = env.num_machines
        self.machine_names: list[str] = list(env.machine_names)
        # 局部观测维度 = 全局 10 + 本机 3
        self.local_obs_dim = OBS_DIM + self.PER_MACHINE_FEATURE_DIM

